if (!msg.attachments || msg.attachments.length === 0) return null;
const pdfs = msg.attachments.filter(a =>
    a.contentType === 'application/pdf' ||
    (a.filename && a.filename.toLowerCase().endsWith('.pdf'))
);
if (pdfs.length === 0) return null;
return [pdfs.map(pdf => ({
    payload: {
        pdf_content:      pdf.content,
        pdf_filename:     pdf.filename,
        email_from:       msg.from,
        email_subject:    msg.topic,
        email_date:       msg.date,
        email_messageId:  msg.messageId
    }
}))];

// Requiere: cd ~/.node-red && npm install pdf-parse
const pdfParse = require('pdf-parse');
const pdfBuffer = Buffer.isBuffer(msg.payload.pdf_content)
    ? msg.payload.pdf_content
    : Buffer.from(msg.payload.pdf_content, 'base64');
pdfParse(pdfBuffer).then(data => {
    msg.payload.pdf_text  = data.text;
    msg.payload.pdf_pages = data.numpages;
    node.send(msg);
}).catch(err => node.error('pdf-parse: ' + err.message, msg));
return null;

// Node-RED solo calcula el hash y empaqueta el texto plano.
// Toda la lógica (parseo, validación, MySQL, SQL Server) está en n8n.
const crypto = require('crypto');
const p = msg.payload;
msg.payload = {
    pdf_text:        p.pdf_text,
    pdf_pages:       p.pdf_pages,
    pdf_filename:    p.pdf_filename,
    pdf_hash:        crypto.createHash('sha256').update(p.pdf_content).digest('hex'),
    email_from:      p.email_from,
    email_subject:   p.email_subject,
    email_date:      p.email_date,
    email_messageId: p.email_messageId,
    fuente:          'EMAIL_IMAP',
    timestamp:       new Date().toISOString()
};
return msg;
